import java.security.SecureRandom
import java.util.Base64
import java.util.Random

const val CHARACTERS = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789"

fun generateSessionId(): String {
    val random = Random()
    val stringBuilder = StringBuilder(32)
    for (i in 0 until 32) stringBuilder.append(CHARACTERS[random.nextInt(CHARACTERS.length)])
    return stringBuilder.toString()
}

fun generateToken(): String {
    val random = SecureRandom()
